      "n": 10,
      "column": "left",
      "text": "Un Jedtaëka Behrni btja:\nBilans. Un Bilana Behrni bi-\nja: Jeus/ un Benjamins/ un E-\nuds/ un Knaenus/ un Setans/\nun Tarsis/ un Akisärs.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Wiſſi tchee irr Jedtaëta\nBehrnt / to Tehwu Naïma\nWirfneeki/ ſtipri warreni Gau-\ndis/ ſeptiſxvadefsmitß tuhkfoschi\nun diwisints/ kas Raxra iſgabje.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ir Supins/ un Upims\nbtja Ira Behrni/ un Usims Ake-\nra Behrni.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Nawtaka Behrni btja:\nJakziels/ un Gunus/ un Jezers/\nun Sallums/ Villas Behrni.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Manaffus Behrni bija:\nEfriels/ kas winnam dſimine:\nun winna leeka Seewa Arami-\nja dsemdeja tam Makiru Gile-\nada Tehwu.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un Makirs nehme Upi-\nmam un Supimam Seewas/\nun winna Mahfat bija Maëka\nWahrda. Un ta ohtra Wahrdṣ\nbija Zelaweads/ un Zelaweadam\nbija Meitas.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un Maktra Seewa Ma-\ncka dsemdeja Dehtu/ un fauze\nwinna Wahrdu Peeres/ un win-\nna Brahta Wahrdṣ btja Sares/\nun winna Dehta Wahrdi btja U-\nlams un Rakems.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un Ulama Behrni btja:\nBedans. Schee bija Gilenda\nBehrni/ ta Dehta Makira Ma-\nnaffus Dehta.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un winna Mahfa Mole-\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un Seimida Behrni bija:\nAkejans/ un Sikens/ un Likus/\nun Aniams.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un Eewratma Behrni bi-\nja: Sutelaks/ un Bereds wit-\nna Dehtṣ / ta Dehtṣ bija Ta-\nkats/ ta Dehtṣ bija Eladus / ta\nDehtṣ bija Takats.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Ta Dehtṣ bija Sabads/\nta Dehtṣ bija Sutelaks/ta Dehtṣ\nbija Eesers un Eeleads. Un tee\nWihti no Gatas/ kas tai Seun-\nmê bija- dsimmutchi / nekawe\ntohs / tapehz ka tee letja nahze\nwinnu Lohpus atxeint.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un Eewraims winnu\nTehws scheblojahs ilgu Laiku /\ntad nahze winna Brahti to ee-\npreezinaht.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Pehz gabje tas pee fawas\nSeewas/ un tatappe gruhta/ un\ndsemdeja weenu Dehtu/un nofan-\nze winna Wahrdü Brijuṣ / ta-\npehz / ka Behdas bija winna\nNamna.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un winna Meita bija\nSeera/ ta ustaitija to Letjas un\nKalna Bet- Ohronu / un Usen-\nSeera.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un Repus bija winna\nDehtṣ/ ta Dehtṣ bija Reseps un\nTelus/ ta Dehtṣ bija Tääus.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Ta Dehtṣ bija Kaëdans/\nta Dehtṣ bija Amjuds/ ta Dehtṣ\nbija Eelisamus.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Ta Dehtṣ bija Nuns/ ta\nDehtṣ bija Josuüs.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un winnu Dsihwoschana\nGgggg un\n"
    }
  ],
